/* eslint-disable @typescript-eslint/no-explicit-any */
import { tipoObjeto } from '../predicados';

/**
 * Copia um objeto. Similar à função `deepCopy` do Python.
 *
 * ```
 * console.log(copiaProfunda({ a: { b: { c: [1, 2, 3] }  } }));
 * Saída: { a: { b: { c: [1, 2, 3] }  } }
 * ```
 * @param alvo
 */
export function clonar(alvo: unknown): unknown {
  if (Array.isArray(alvo)) {
    return alvo.map((item) => clonar(item));
  }
  if (tipoObjeto(alvo)) {
    const keys = Object.keys(alvo) as Array<keyof typeof alvo>;
    return keys.reduce((r, k): any => {
      r[k] = clonar(alvo[k]);
      return r;
    }, {} as Record<string, any>);
  }
  return alvo;
}
