import { tipo, tipoObjeto, tipoData } from '../predicados';

/**
 * Verifica se dois valores, objetos ou vetores são iguais.
 * No caso de objetos e vetores, a comparação é profunda.
 *
 * Uso:
 * ```
 * console.log(igual([null, NaN, { a: [], b: }, 1, 2, 3], [null, NaN, { a: [], b: }, 1, 2, 3]));
 * // Saída: true
 * ```
 * @param a
 * @param b
 */
export function igual(a: unknown, b: unknown): boolean {
  if (tipo(a) !== tipo(b)) {
    return false;
  }
  if (Array.isArray(a) && Array.isArray(b)) {
    return a.length === b.length && a.every((v, i) => igual(v, b[i]));
  }
  if (tipoObjeto(a) && tipoObjeto(b)) {
    const keysA = Object.keys(a) as Array<keyof typeof a> | Array<keyof typeof b>;
    const keysB = Object.keys(b) as Array<keyof typeof b> | Array<keyof typeof a>;
    const sameKeys = igual(keysA, keysB);
    return sameKeys && keysA.every((key) => igual(a[key], b[key]));
  }
  if (tipoData(a) && tipoData(b)) {
    return a.valueOf() === b.valueOf();
  }
  return Object.is(a, b);
}
