import { tipoString, tipoObjeto, tipoData, tipoNumero } from '../predicados';

/**
 * Filtra um vetor retornando somente os itens que contêm o parâmetro de busca.
 * Primeiro converte os itens do vetor no seu formato string correspondente.
 *
 * **Uso:**
 * ```
 * const vetor = [
 *   { a: 'one is a word' },
 *   { b: 'two is a word' },
 *   { c: new Date('2020-01-01') }
 * ];
 * const busca = 'two';
 * console.log(filtrarComoString(vetor, busca));
 * // Saída: [ { b: 'two is a word' } ]
 * ```
 *
 * @param vetor Vetor de entrada
 * @param buscar Parâmetro de busca
 */
export function filtrarComoString(vetor: unknown[], buscar: string): unknown[] {
  if (!Array.isArray(vetor)) {
    throw new Error('O primeiro argumento deve ser um vetor!');
  }
  if (!tipoString(buscar)) {
    throw new Error('O segundo argumento deve ser uma string!');
  }
  return vetor.filter((item) => {
    const text = getAsString(item).toLowerCase();
    return text.indexOf(buscar) >= 0;
  });
}

function getAsString(o: unknown): string {
  if (tipoString(o)) {
    return o;
  }
  if (Array.isArray(o)) {
    return o.map((item) => getAsString(item)).join('\n');
  }
  if (tipoObjeto(o)) {
    const keys = Object.keys(o) as Array<keyof typeof o>;
    return keys.map((key) => (tipoString(key) ? getAsString(o[key]) : '')).join('\n');
  }
  if (tipoData(o)) {
    return o.toLocaleDateString('pt-BR', { timeZone: 'UTC' });
  }
  if (tipoNumero(o)) {
    return o.toString();
  }
  return '';
}
