/**
 * Implementa merge sort com um comparador customizado.
 *
 * @param valores
 * @param comparador
 * @param inicio
 * @param fim
 */
export function mergeSort<T>(
  valores: T[],
  comparador: (a: T, b: T) => boolean,
  inicio = 0,
  fim = valores.length - 1
): void {
  if (inicio < fim) {
    const meio = Math.floor((inicio + fim) / 2);
    mergeSort(valores, comparador, inicio, meio);
    mergeSort(valores, comparador, meio + 1, fim);
    merge(valores, inicio, meio, fim, comparador);
  }
}

function merge<T>(valores: T[], inicio: number, meio: number, fim: number, comparador: (a: T, b: T) => boolean) {
  const aux = new Array(fim - inicio + 1);

  for (let i = inicio; i <= meio; i++) {
    aux[i] = valores[i];
  }
  for (let j = meio + 1; j <= fim; j++) {
    aux[fim + meio + 1 - j] = valores[j];
  }

  let low = inicio;
  let high = fim;

  for (let i = inicio; i <= fim; i++) {
    if (comparador(aux[high], aux[low])) {
      valores[i] = aux[low];
      low++;
    } else {
      valores[i] = aux[high];
      high--;
    }
  }
}
