import { tipoNumero, tipoString } from '../predicados';

export function checarDigitos(str: string | number, tipo = 'cpf'): boolean {
  const numeros = obterNumeros(str, tipo);
  if (Array.isArray(numeros)) {
    const pesos = obterPesos(numeros.length);
    if (Array.isArray(pesos)) {
      const base = numeros.slice(0, -2);
      const [primeiro, segundo] = numeros.slice(-2);
      return obterDigito(base, pesos.slice(1)) === primeiro && obterDigito(base.concat(primeiro), pesos) === segundo;
    }
    return false;
  }
  return false;
}

function obterNumeros(str: string | number, tipo: string): number[] | boolean {
  if (tipoNumero(str)) {
    str = str.toString();
  }
  if (!tipoString(str)) {
    return false;
  }
  str = str.replace(/[^\d]+/g, '');
  const tamanho = tipo === 'cnpj' ? 14 : 11;
  if (str.length !== tamanho) {
    return false;
  }
  const invalid = [...Array(tamanho - 1).keys()].map((x) => String(x).repeat(tamanho));
  if (invalid.indexOf(str) >= 0) {
    return false;
  }
  return str.split('').map(Number);
}

function obterPesos(tamanho: number) {
  const pesos = {
    cpf: [11, 10, 9, 8, 7, 6, 5, 4, 3, 2],
    cnpj: [6, 5, 4, 3, 2, 9, 8, 7, 6, 5, 4, 3, 2]
  };
  if (tamanho === 11) {
    return pesos.cpf;
  }
  if (tamanho === 14) {
    return pesos.cnpj;
  }
  return false;
}

function obterDigito(numeros: number[], pesos: number[]) {
  const produtos = numeros.map((numero, i) => numero * pesos[i]);
  const soma = produtos.reduce((soma, produto) => (soma += produto), 0);
  return ((soma * 10) % 11) % 10;
}
